-- Generado desde catalogo_tramites.csv (no editar a mano).
update public.tramites t set
  categoria = v.categoria,
  datos_requeridos = v.datos_requeridos,
  prerequisitos_reales = v.prerequisitos_reales,
  ambito = v.ambito,
  nivel_automatizacion = v.nivel_automatizacion,
  que_se_automatiza = v.que_se_automatiza,
  que_queda_manual = v.que_queda_manual,
  validaciones_requeridas = v.validaciones_requeridas,
  requiere_credenciales_cliente = v.requiere_credenciales_cliente,
  precio_publico = v.precio_publico,
  precio_mayorista = v.precio_mayorista
from (values
  ('SAT', 'Constancia de Situación Fiscal (con contraseña)', 'RFC, contraseña del portal del SAT, correo electrónico', 'Estar inscrito en el RFC y tener Contraseña (CIEC) activa o e.firma vigente. Si olvidó la contraseña, primero hay que recuperarla. Se genera en el portal o app SAT Móvil.', 'Federal (SAT)', 'Nivel 1 - Asistido/Orquestación', 'Intake, validación de RFC, checklist de prerrequisitos, cobro, seguimiento y entrega del PDF.', 'El login con Contraseña/e.firma y la descarga los hace el cliente o el admin en vivo (sin almacenar credenciales).', 'Confirmar que el cliente YA tiene RFC y Contraseña/e.firma vigente. Validar formato RFC (13 con homoclave). Si no recuerda la contraseña, derivar primero a ''Recuperación de contraseña SAT''.', 'Sí (Contraseña/e.firma del cliente - NO almacenar)', 80, 40),
  ('SAT', 'Constancia de Situación Fiscal EXPRES (sin contraseña)', 'CURP', 'Ya estar inscrito en el RFC. Vía SAT ID (satid.sat.gob.mx): persona física mayor de 18 años, INE vigente, correo y celular propios y grabar un video de validación. La entrega NO es inmediata (puede tardar hasta ~5 días hábiles).', 'Federal (SAT)', 'Nivel 1 - Asistido/Orquestación', 'Intake, validación de CURP/RFC, checklist (INE, correo, celular), cobro y seguimiento; recordatorio de que la entrega tarda hasta ~5 días hábiles.', 'La validación de identidad en SAT ID (video/selfie + INE) la realiza el propio cliente; el admin no puede suplantarla.', 'Confirmar inscripción en RFC y edad >=18. Validar INE legible (OCR), correo y celular propios. Advertir que NO es entrega inmediata.', 'Parcial (validación de identidad en vivo del cliente)', 300, 200),
  ('SAT', 'Constancia de Situación Fiscal (sin contraseña)', 'CURP', 'Ya estar inscrito en el RFC. Se obtiene con RFC+CURP en SAT Móvil o vía SAT ID con INE, correo y celular. Si no se conoce el RFC, se consulta antes con la CURP en el portal del SAT.', 'Federal (SAT)', 'Nivel 1 - Asistido/Orquestación', 'Intake, validación, cobro, seguimiento y entrega (vía SAT ID / SAT Móvil).', 'Validación de identidad (SAT ID) o login en la app la hace el cliente; descarga.', 'Confirmar inscripción en RFC; si no se conoce el RFC, consultarlo antes con la CURP. Validar INE, correo y celular.', 'Parcial (identidad/app del cliente)', 250, 165),
  ('SAT', 'Recuperación de contraseña SAT', 'RFC, correo registrado, celular', 'Estar inscrito en el RFC y tener un correo o celular previamente registrados ante el SAT, o e.firma vigente. Si no hay medios de contacto registrados, se requiere e.firma o acudir con cita presencial.', 'Federal (SAT)', 'Nivel 1 - Asistido/Orquestación', 'Intake, verificación de prerrequisitos, guía paso a paso y seguimiento.', 'El OTP/correo de recuperación llega a los medios del cliente y la e.firma la usa él; el admin solo asiste.', 'Confirmar que el cliente tiene correo/celular registrados ante el SAT o e.firma vigente. Si no, advertir que será necesaria cita presencial.', 'Parcial (OTP/e.firma del cliente)', 100, 50),
  ('SAT', 'Opinión de cumplimiento', 'RFC, contraseña SAT', 'RFC activo con Contraseña o e.firma. Debe estar al corriente en declaraciones y obligaciones; de lo contrario la opinión saldrá ''negativa''. No tener domicilio como no localizado.', 'Federal (SAT)', 'Nivel 1 - Asistido/Orquestación', 'Intake, validación de RFC, cobro, seguimiento y entrega del PDF.', 'Login con Contraseña/e.firma del cliente; el resultado (positiva/negativa) depende de su situación fiscal.', 'Confirmar RFC activo y al corriente. Advertir que con adeudos saldrá ''negativa''.', 'Sí (Contraseña/e.firma - NO almacenar)', 200, 100),
  ('SAT', 'Actualización de datos RFC', 'RFC, contraseña SAT, dato a actualizar', 'RFC activo con Contraseña o e.firma. Tener el documento que respalde el cambio (p. ej. comprobante de domicilio reciente para cambio de domicilio).', 'Federal (SAT)', 'Nivel 1 - Asistido/Orquestación', 'Intake, captura del dato a cambiar, checklist de soporte (p.ej. comprobante de domicilio) y seguimiento.', 'Login del cliente y captura en el portal del SAT.', 'Validar RFC activo + Contraseña/e.firma. Exigir documento que respalde el cambio (OCR de comprobante de domicilio si aplica).', 'Sí (Contraseña/e.firma - NO almacenar)', 140, 70),
  ('SAT', 'CITA SAT', 'CURP, nombre completo, correo electrónico, teléfono de contacto, ciudad o estado donde deseas la cita', 'Tener CURP/RFC, correo y teléfono. Depende por completo de la disponibilidad de fichas en citas.sat.gob.mx, que suele ser limitada (hay que monitorear liberaciones).', 'Federal (SAT)', 'Nivel 2 - Semiautomático', 'Intake, monitoreo de disponibilidad en citas.sat.gob.mx y aviso al cliente cuando se libere ficha.', 'El agendado final lo confirma una persona. NO auto-reservar: viola los ToS y el sistema lo bloquea.', 'Validar CURP/RFC, correo y teléfono. Indicar servicio/oficina deseada.', 'No', 150, 100),
  ('Documentos personales', 'CURP actualizada', 'Nombre completo, fecha de nacimiento, estado', 'Estar registrado en el Registro Nacional de Población (haber sido inscrito en el Registro Civil). Es gratuita en gob.mx/curp. Si hay error en datos, se corrige con acta de nacimiento (CURP certificada).', 'Nacional (RENAPO)', 'Nivel 3 - Casi automático', 'Captura de nombre/apellidos/fecha/estado, pre-llenado y deep-link al portal, entrega del PDF.', 'Resolver el captcha y descargar (último paso en gob.mx/curp). No hay API pública.', 'Validar estructura de la CURP resultante (18 caracteres + dígito verificador). Si hay error en datos, derivar a corrección con acta.', 'No', 10, 5),
  ('Documentos personales', 'Actas de nacimiento certificadas', 'Nombre completo, fecha de nacimiento, estado, padres (CURP)', 'Que el nacimiento esté registrado y DIGITALIZADO en el Registro Civil. Se requiere CURP. Si el acta no está digitalizada en la base nacional, hay que acudir al Registro Civil del estado donde se registró.', 'Nacional / Estatal (Registro Civil)', 'Nivel 2 - Semiautomático', 'Captura por CURP, pre-llenado, cobro de derechos + tu tarifa, seguimiento y entrega.', 'Pago de derechos y descarga; el portal federal puede exigir Llave MX. Si el acta no está digitalizada, requiere acudir al Registro Civil estatal.', 'Validar CURP. Verificar que el acta esté digitalizada. Advertir requisito de Llave MX en el portal federal.', 'Parcial (Llave MX si se usa el portal federal)', 120, 60),
  ('Documentos personales', 'Duplicado de certificado nivel básico', 'Acta de nacimiento del estudiante / CURP / INE / copia certificado o boleta', 'Que el alumno haya concluido el nivel y que el certificado exista en el control escolar de la SEP estatal. CURP y datos de la escuela (CCT). En algunos estados es trámite presencial ante la autoridad educativa.', 'Estatal (SEP / control escolar)', 'Nivel 1 - Asistido', 'Intake, checklist (CURP, INE, datos de la escuela/CCT) y seguimiento.', 'Gestión ante control escolar/SEP estatal; muchas veces presencial y sujeto a que el certificado exista en el sistema.', 'Validar CURP y CCT de la escuela. Confirmar nivel concluido.', 'No', 60, 30),
  ('IMSS', 'Número de Seguro Social', 'CURP, correo, código postal', 'Tener CURP y no contar ya con un NSS asignado (si ya tiene uno, es ''consulta'', no ''asignación''). Se obtiene en línea en IMSS Digital con CURP y correo.', 'Federal (IMSS)', 'Nivel 2 - Semiautomático', 'Captura CURP+correo, pre-llenado en IMSS Digital y entrega del documento.', 'Verificación por correo (OTP) del cliente y captcha.', 'Validar CURP. Confirmar que NO tenga ya un NSS (si lo tiene, es consulta, no asignación).', 'Parcial (verificación por correo del cliente)', 60, 30),
  ('IMSS', 'Semanas cotizadas IMSS', 'CURP, NSS, correo', 'Tener un NSS asignado y haber cotizado (haber trabajado formalmente). CURP y NSS deben coincidir en el sistema del IMSS. El reporte llega en PDF al correo. Si nunca cotizó, no habrá semanas que mostrar.', 'Federal (IMSS)', 'Nivel 2 - Semiautomático', 'Captura CURP+NSS+correo, pre-llenado y entrega del PDF (llega al correo).', 'Captcha/verificación y revisión del cliente.', 'Validar NSS (11 dígitos) y CURP, y que coincidan. Confirmar que el cliente cotizó (tiene NSS asignado).', 'Parcial (el correo del cliente recibe el PDF)', 80, 40),
  ('Becas y educación', 'Registro de becas', 'CURP alumno, CURP tutor, domicilio, teléfono', 'Cuenta Llave MX del tutor (NO del alumno). CURP certificada de tutor y alumno, INE vigente y comprobante de domicilio del tutor, y CCT de la escuela. El alumno debe estar inscrito en escuela pública. Solo se puede registrar dentro de los periodos oficiales abiertos.', 'Federal (Becas Bienestar)', 'Nivel 1 - Asistido/Orquestación', 'Intake, validación de prerrequisitos (CURP certificada de tutor y alumno, CCT, escuela pública), OCR de INE y comprobante, alertas de ventana de registro y seguimiento.', 'Login con Llave MX del tutor y carga de documentos; lo hace el tutor o el admin en vivo. Solo dentro del periodo oficial.', 'Verificar CURP certificada (leyenda ''Verificada con Registro Civil''), CCT válida, alumno en escuela pública, INE y comprobante vigentes. BLOQUEAR si el periodo de registro está cerrado.', 'Sí (Llave MX del tutor - NO almacenar)', 100, 50),
  ('Otros trámites', 'Citas para trámites', 'CURP o RFC, nombre, teléfono, correo', 'Depende del trámite destino. En general CURP/RFC, correo y teléfono, y que haya disponibilidad de citas en el sistema de la dependencia correspondiente.', 'Varía', 'Nivel 2 - Semiautomático', 'Intake, monitoreo de disponibilidad y aviso al cliente.', 'Confirmación del agendado por una persona (no auto-reservar).', 'Validar CURP/RFC, nombre, teléfono, correo. Identificar el trámite destino y sus requisitos.', 'No', 150, 75),
  ('Trámites legales y administrativos', 'Certificado de no antecedentes penales', 'CUTS, contraseña, INE', 'Trámite estatal (Edomex): tener cuenta CUTS activa y validada, INE vigente y cubrir el pago de derechos. Para el certificado FEDERAL el trámite es distinto (OADPRS, con CURP, acta, INE y comprobante de domicilio).', 'Edomex (CUTS)', 'Nivel 1 - Asistido', 'Intake, validación de prerrequisitos, cobro de derechos + tu tarifa, seguimiento y entrega.', 'Acceso con la cuenta CUTS del cliente y descarga.', 'Confirmar cuenta CUTS validada e INE. Distinguir si el cliente necesita la versión FEDERAL (otro trámite/portal OADPRS).', 'Sí (CUTS del cliente - NO almacenar)', 60, 30),
  ('Trámites legales y administrativos', 'No deudor alimentario moroso nacional', 'CURP', 'Solo requiere CURP: es una consulta en el registro de deudores alimentarios. La cobertura entre estados aún es parcial, por lo que un resultado ''sin registro'' no garantiza cobertura en todas las entidades.', 'Nacional (REDAM)', 'Nivel 3 - Casi automático', 'Consulta por CURP, pre-llenado y entrega.', 'Captcha y descarga.', 'Validar CURP. Advertir que la cobertura entre estados es parcial (un ''sin registro'' no garantiza todas las entidades).', 'No', 20, 10),
  ('Trámites legales y administrativos', 'No deudor alimentario moroso estatal', 'CUTS, contraseña, línea de pago', 'Trámite estatal (Edomex): cuenta CUTS activa y línea de pago/pago de derechos cubierto.', 'Edomex (CUTS)', 'Nivel 1 - Asistido', 'Intake, cobro, seguimiento y entrega.', 'Acceso con CUTS del cliente + línea de pago de derechos.', 'Confirmar cuenta CUTS. Validar línea de pago.', 'Sí (CUTS del cliente - NO almacenar)', 120, 60),
  ('Trámites legales y administrativos', 'Constancia de no inhabilitación', 'Datos personales', 'Tener RFC a 13 posiciones (con homoclave) y CURP. Hay que generar línea de captura y pagar derechos (~$222-240); la constancia se descarga ~2 días hábiles después de validado el pago. La emite la Secretaría Anticorrupción y Buen Gobierno (antes SFP).', 'Federal (SABG, antes SFP)', 'Nivel 2 - Semiautomático', 'Captura RFC+CURP, generación de la línea de captura, cobro, recordatorio de espera (~2 días hábiles tras el pago), seguimiento y entrega.', 'Pago de derechos (~$222-240) en banco/portal; descarga tras validar el pago.', 'Validar RFC (13 con homoclave) y CURP. Aclarar si requiere ''no inhabilitación'' o ''no existencia de sanción'' (son distintas).', 'No', 50, 25),
  ('Trámites legales y administrativos', 'Constancia de recepción de denuncia', 'CURP, INE, estado civil, datos de los hechos, correo, teléfono', 'CURP e INE del denunciante y datos reales de los hechos. Es la constancia que emite la Fiscalía/MP al presentar una denuncia; requiere relatar hechos concretos (no es un documento de mero registro de datos).', 'Edomex (Fiscalía)', 'Nivel 2 - Semiautomático', 'Intake estructurado de los hechos, checklist (CURP, INE, estado civil, correo, teléfono) y seguimiento.', 'La narración de hechos debe ser real y la presenta el cliente; el admin no puede fabricarla.', 'Validar CURP/INE y que los campos de los hechos estén completos. Marcar como DATO SENSIBLE.', 'No', 45, 22.5),
  ('Citas y trámites de gobierno', 'Citas para trámites de gobierno', 'CURP o RFC, nombre, teléfono, correo', 'Depende del trámite destino. En general CURP/RFC, correo y teléfono, y disponibilidad de fichas en el sistema de la dependencia.', 'Varía', 'Nivel 2 - Semiautomático', 'Intake, monitoreo de disponibilidad y aviso.', 'Confirmación del agendado (no auto-reservar).', 'Validar CURP/RFC, nombre, teléfono, correo. Identificar la dependencia destino.', 'No', 80, 40),
  ('Citas y trámites de gobierno', 'Cita INE', 'Datos solicitados por el sistema', 'Acceso al portal del INE y disponibilidad de citas. Para la credencial al acudir al módulo se necesita: acta de nacimiento, identificación con foto, comprobante de domicilio y CURP.', 'Nacional (INE)', 'Nivel 2 - Semiautomático', 'Intake, monitoreo de disponibilidad, aviso y checklist de ''qué llevar'' (acta, ID con foto, comprobante, CURP).', 'Agendado final y comparecencia presencial en el módulo.', 'Capturar los datos que pide el sistema INE y validar completitud.', 'No', 45, 22.5),
  ('Citas y trámites de gobierno', 'Cita pasaporte mexicano', 'CURP, datos personales, vigencia y número de pasaporte si es renovación', 'CURP, correo activo y un celular MEXICANO (el sistema citas.sre.gob.mx envía código por SMS). La disponibilidad de citas es muy limitada. Para el trámite el día de la cita: acta de nacimiento certificada, INE vigente y pago de derechos; si es renovación, el pasaporte anterior.', 'Federal (SRE)', 'Nivel 2 - Semiautomático', 'Intake, monitoreo de fichas (muy escasas), aviso al cliente y checklist (acta certificada, INE, pago) + ''qué llevar''.', 'Agendado final (no auto-reservar) en citas.sre.gob.mx; verificación por SMS al celular del cliente; trámite presencial con biometría.', 'Validar CURP, correo activo y celular MEXICANO. En renovación, datos del pasaporte anterior. Advertir disponibilidad limitada.', 'Parcial (SMS al celular del cliente)', 300, 150),
  ('Citas y trámites de gobierno', 'CUTS (Cuenta Única de Trámites y Servicios)', 'CURP, datos generales, domicilio, correo electrónico, INE', 'Identidad digital del Estado de México (en realidad ''Clave Única de Trámites y Servicios''). Requiere CURP, correo electrónico personal y crear contraseña; RFC si es persona moral. Para la CUTS ''validada'' hay que acudir a un módulo.', 'Edomex (ADEM)', 'Nivel 1 - Asistido/Orquestación', 'Intake, validación de CURP/RFC, checklist (correo, domicilio, INE) y guía paso a paso.', 'El cliente crea su propia contraseña/identidad; es personal e intransferible.', 'Validar CURP y correo personal. Verificar que no exista ya una cuenta (homónimos).', 'Sí (crea credencial propia del cliente - NO almacenar)', 60, 30),
  ('Citas y trámites de gobierno', 'Llave MX', 'Correo electrónico, CURP del tutor o titular, número de teléfono', 'CURP válida (de preferencia certificada por el Registro Civil) y acceso REAL a un correo y a un celular propios; código postal/domicilio y crear contraseña. Es única por persona. Para nivel ''Verificada'' se exige INE, e.firma o pasaporte.', 'Nacional/Federal (ATDT)', 'Nivel 1 - Asistido/Orquestación', 'Intake, validación de CURP (de preferencia certificada), checklist (CP, correo, celular) y guía.', 'El cliente crea su contraseña; OTP a su correo/celular; cuenta única por persona.', 'Validar CURP certificada y acceso real a correo y celular. Para nivel ''Verificada'' se requiere INE/e.firma/pasaporte.', 'Sí (crea credencial propia del cliente - NO almacenar)', 25, 12.5),
  ('Servicios y pagos', 'Recibo CFE', 'Número de servicio, nombre del titular, monto a pagar', 'Tener el número de servicio (aparece en un recibo previo) y que el servicio esté activo a nombre del titular. Es una reimpresión/consulta, no da de alta el servicio.', 'CFE (paraestatal)', 'Nivel 3 - Casi automático', 'Captura del número de servicio, consulta/reimpresión y entrega.', 'Captcha y descarga; el servicio debe estar a nombre del titular.', 'Validar número de servicio (RPU) y que el servicio esté activo.', 'No', 20, 10),
  ('Servicios y pagos', 'Pago agua CDMX', 'Número de cuenta', 'Número de cuenta del SACMEX y que el predio/servicio doméstico esté registrado. Aplica solo a la Ciudad de México.', 'CDMX (SACMEX)', 'Nivel 2 - Semiautomático', 'Captura del número de cuenta, consulta del adeudo/monto, generación de línea/boleta y seguimiento.', 'El pago lo autoriza el cliente; descarga del comprobante.', 'Validar número de cuenta SACMEX y servicio doméstico registrado en CDMX.', 'No', 20, 10),
  ('Servicios y pagos', 'Predial', 'Clave catastral', 'Clave catastral del inmueble y que el predio esté registrado en la tesorería del municipio/alcaldía correspondiente.', 'Municipal', 'Nivel 2 - Semiautomático', 'Captura de la clave catastral, consulta del monto, generación de línea/boleta y seguimiento.', 'Pago de derechos por el cliente; descarga.', 'Validar clave catastral y que el predio esté registrado en la tesorería del municipio correcto.', 'No', 25, 12.5),
  ('Servicios y pagos', 'Tenencia', 'Datos del vehículo', 'Vehículo emplacado/registrado en la entidad y datos del vehículo (placa). El cálculo depende de la entidad y de si hay adeudos de ejercicios anteriores.', 'Estatal', 'Nivel 2 - Semiautomático', 'Captura de datos del vehículo, consulta del monto/adeudos, generación de línea y seguimiento.', 'Pago por el cliente; descarga.', 'Validar placa/datos del vehículo y entidad de registro. Revisar adeudos de ejercicios previos.', 'No', 20, 10),
  ('Salud y comprobantes', 'Resultados laboratorios Salud Digna', 'Ticket, nombre completo, fecha de nacimiento, tipo de estudio', 'Haberse realizado el estudio en Salud Digna y conservar el ticket/folio. Los resultados solo se liberan cuando el laboratorio los publica (no están disponibles de inmediato).', 'Privado (Salud Digna)', 'Nivel 2 - Semiautomático', 'Captura de ticket/folio + datos del paciente, consulta y entrega del PDF.', 'Solo disponible cuando el laboratorio libera resultados; descarga.', 'Validar ticket/folio y datos del paciente. DATO SENSIBLE (salud): minimizar, cifrar y borrar tras la entrega.', 'No', 20, 10),
  ('Salud y comprobantes', 'Certificado de discapacidad permanente', 'CURP', 'CURP y, sobre todo, contar con una discapacidad ya valorada/diagnosticada por una institución de salud (IMSS/ISSSTE/Secretaría de Salud). Suele requerir valoración médica previa; no es un trámite meramente documental.', 'Federal/Salud', 'Nivel 0 - No automatizable', 'Intake, agendado de valoración, checklist y preparación de expediente.', 'Requiere valoración médica presencial por institución de salud; no es trámite documental.', 'Validar CURP. Confirmar que existe diagnóstico/valoración previa. DATO SENSIBLE (salud).', 'No', 30, 15),
  ('Comprobantes laborales', 'Comprobante pago jubilados ISSSTE', 'Número de pensión, código de deudo, año', 'Ser pensionado/jubilado del ISSSTE. Número de pensión y código de deudo; acceso al portal de pensionados.', 'Federal (ISSSTE)', 'Nivel 1 - Asistido', 'Intake, validación (número de pensión, código de deudo, año), seguimiento y entrega.', 'Acceso al portal de pensionados con datos del cliente; descarga.', 'Validar número de pensión y código de deudo. Confirmar que es pensionado ISSSTE.', 'Sí (acceso al portal del cliente - NO almacenar)', 20, 10),
  ('Comprobantes laborales', 'Comprobante pago ISSEMYM', 'Usuario y contraseña', 'Ser derechohabiente/pensionado del ISSEMYM y contar con usuario y contraseña activos del portal.', 'Edomex (ISSEMYM)', 'Nivel 1 - Asistido', 'Intake, seguimiento y entrega.', 'Login con usuario y contraseña del cliente; descarga.', 'Confirmar derechohabiente/pensionado ISSEMYM con credenciales activas.', 'Sí (usuario/contraseña del cliente - NO almacenar)', 20, 10),
  ('Comprobantes laborales', 'Comprobante pago maestros Edo. Méx', 'Usuario y contraseña', 'Ser docente del Estado de México y tener usuario y contraseña del sistema de nómina (SEIEM / Servicios Educativos).', 'Edomex (SEIEM/SE)', 'Nivel 1 - Asistido', 'Intake, seguimiento y entrega.', 'Login con usuario y contraseña del docente; descarga.', 'Confirmar que es docente del Edomex con credenciales del sistema de nómina.', 'Sí (usuario/contraseña del cliente - NO almacenar)', 20, 10)
) as v(categoria, nombre, datos_requeridos, prerequisitos_reales, ambito,
       nivel_automatizacion, que_se_automatiza, que_queda_manual,
       validaciones_requeridas, requiere_credenciales_cliente,
       precio_publico, precio_mayorista)
where t.nombre = v.nombre;
